#!/usr/bin/env python3
# TurnIt resource fix - run from repo root: python3 decode_turnit_fix.py
# Fixes: duplicate Theme.TurnIt, MSG_USER/AI import errors, Manifest theme
import base64, os

ROOT = "."
def w(p, d):
    f = os.path.join(ROOT, p)
    dd = os.path.dirname(f)
    if dd: os.makedirs(dd, exist_ok=True)
    open(f, "wb").write(base64.b64decode(d))
    print(f"  WROTE  {p}")

print("=== TurnIt Resource Fix ===")

# Remove old files that caused duplication
STALE = [
    "app/src/main/res/values/styles.xml",
]
for s in STALE:
    if os.path.exists(s):
        os.remove(s)
        print(f"  DELETED {s}")
    else:
        print(f"  SKIP    {s} (not found)")

w('app/src/main/res/values/themes.xml', "")
w('app/src/main/res/values/colors.xml', "PD94bWwgdmVyc2lvbj0iMS4wIiBlbmNvZGluZz0idXRmLTgiPz4KPHJlc291cmNlcz4KICAgIDwhLS0gUmVmZXJlbmNlZCBieSB0aGVtZXMueG1sIC0gbXVzdCBleGlzdC4gLS0+CiAgICA8Y29sb3IgbmFtZT0icXhfdm9pZF9ibGFjayI+I0ZGMEIwRTE0PC9jb2xvcj4KPC9yZXNvdXJjZXM+Cg==")
w('app/src/main/res/values/strings.xml', "PD94bWwgdmVyc2lvbj0iMS4wIiBlbmNvZGluZz0idXRmLTgiPz4KPHJlc291cmNlcz4KICAgIDxzdHJpbmcgbmFtZT0iYXBwX25hbWUiPlR1cm5JdDwvc3RyaW5nPgo8L3Jlc291cmNlcz4K")
w('app/src/main/AndroidManifest.xml', "")
w('app/src/main/java/com/turnit/app/ui/Composables.kt', "")

print()
print("=== DONE: 4 files written ===")
print()
print("Import constants in MainActivity:")
print("  import com.turnit.app.ui.MSG_USER")
print("  import com.turnit.app.ui.MSG_AI")
